function koshopPublicAction($Params) {
    if (isset($Params['user_parameters']['action']) && $Params['user_parameters']['action'] !== '') {
        return (string)$Params['user_parameters']['action'];
    }

    if (isset($Params['user_parameters_unordered']['action']) && $Params['user_parameters_unordered']['action'] !== '') {
        return (string)$Params['user_parameters_unordered']['action'];
    }

    $uri = isset($_SERVER['REQUEST_URI']) ? (string)$_SERVER['REQUEST_URI'] : '';

    if (preg_match('#/koshopchat/public/(start|send|messages|upload)(?:[/?#]|$)#', $uri, $m)) {
        return $m[1];
    }

    if (preg_match('#/koshopchat/public/\(action\)/(start|send|messages|upload)(?:[/?#]|$)#', $uri, $m)) {
        return $m[1];
    }

    return 'start';
}
